+			t.Fatal("rig 'forkrig' not found in rigs.json")
+		}
+		if entry.UpstreamURL != upstreamURL {
+			t.Errorf("rigs.json UpstreamURL = %q, want %q", entry.UpstreamURL, upstreamURL)
+		}
+	})
